    ex, ey = end
    dx = ex - sx
    dy = ey - sy
    length = math.sqrt(dx * dx + dy * dy)
    if length == 0:
        return
    ux, uy = dx / length, dy / length
    nx, ny = -uy, ux  # normal

    # Resistor occupies middle 60% of the segment
    margin = 0.2
    num_zigs = 6
    r_start = margin
    r_end = 1.0 - margin

    # Draw wire segments before and after resistor
    rs_x = sx + dx * r_start
    rs_y = sy + dy * r_start
    re_x = sx + dx * r_end
    re_y = sy + dy * r_end

    pygame.draw.line(surface, WIRE_COLOR, (int(sx), int(sy)), (int(rs_x), int(rs_y)), WIRE_WIDTH)
    pygame.draw.line(surface, WIRE_COLOR, (int(re_x), int(re_y)), (int(ex), int(ey)), WIRE_WIDTH)

    # Draw zigzag
    zig_len = (r_end - r_start) / num_zigs
    amplitude = 12
    points = []
    points.append((int(rs_x), int(rs_y)))
    for i in range(num_zigs):
        t = r_start + zig_len * (i + 0.5)
        px = sx + dx * t
        py = sy + dy * t
        side = 1 if i % 2 == 0 else -1
        px += nx * amplitude * side
        py += ny * amplitude * side
        points.append((int(px), int(py)))
    points.append((int(re_x), int(re_y)))
    pygame.draw.lines(surface, color, False, points, 3)

    # Label
    mid_x = (sx + ex) / 2
    mid_y = (sy + ey) / 2
    offset = 28
    label_x = mid_x + nx * offset
    label_y = mid_y + ny * offset

    text = font_medium.render(f"{label}={value:.0f}Ω", True, color)
    rect = text.get_rect(center=(int(label_x), int(label_y)))
    surface.blit(text, rect)

