def draw_current_arrow_on_path(surface, path, progress, color, size=8):
    """Draw an animated current dot/arrow along a path defined by list of points."""
    # Calculate total path length
    segments = []
    total_len = 0
    for i in range(len(path) - 1):
        dx = path[i + 1][0] - path[i][0]
        dy = path[i + 1][1] - path[i][1]
        seg_len = math.sqrt(dx * dx + dy * dy)
        segments.append(seg_len)
        total_len += seg_len

    if total_len == 0:
        return

    # Find position at progress
    target_dist = (progress % 1.0) * total_len
    accumulated = 0
    for i in range(len(segments)):
        if accumulated + segments[i] >= target_dist:
            t = (target_dist - accumulated) / segments[i] if segments[i] > 0 else 0
            x = path[i][0] + (path[i + 1][0] - path[i][0]) * t
            y = path[i][1] + (path[i + 1][1] - path[i][1]) * t

            # Direction for arrow
            dx = path[i + 1][0] - path[i][0]
            dy = path[i + 1][1] - path[i][1]
            seg_len = segments[i]
            if seg_len > 0:
                ux, uy = dx / seg_len, dy / seg_len
            else:
                ux, uy = 1, 0

            # Draw arrow (triangle)
            tip_x = x + ux * size
            tip_y = y + uy * size
            left_x = x - ux * size * 0.7 + (-uy) * size * 0.5
            left_y = y - uy * size * 0.7 + ux * size * 0.5
            right_x = x - ux * size * 0.7 - (-uy) * size * 0.5
            right_y = y - uy * size * 0.7 - ux * size * 0.5

            pygame.draw.polygon(surface, color, [
                (int(tip_x), int(tip_y)),
                (int(left_x), int(left_y)),
                (int(right_x), int(right_y))
            ])
            # Glow effect
            pygame.draw.circle(surface, color, (int(x), int(y)), size // 2 + 2)
            return
        accumulated += segments[i]


def draw_mesh_arrow(surface, center, radius, clockwise, label, color):
    """Draw a circular arrow indicating mesh current direction."""
    cx, cy = center
    # Draw arc
